import{_ as e,o as d,c as r,ai as a}from"./chunks/framework.CaiDwmc7.js";const m=JSON.parse('{"title":"ElectronPrismController","description":"Thin platform shell extending BasePrismController, VS Code API replacements, services, and handler registry.","frontmatter":{"title":"ElectronPrismController","description":"Thin platform shell extending BasePrismController, VS Code API replacements, services, and handler registry.","outline":[2,3]},"headers":[],"relativePath":"electron/controller.md","filePath":"electron/controller.md","lastUpdated":1772487797000}'),s={name:"electron/controller.md"};function o(i,t,n,c,l,h){return d(),r("div",null,[...t[0]||(t[0]=[a(`<h1 id="electronprismcontroller" tabindex="-1">ElectronPrismController <a class="header-anchor" href="#electronprismcontroller" aria-label="Permalink to “ElectronPrismController”">​</a></h1><h2 id="src-hosts-electron-electronprismcontroller-ts" tabindex="-1"><code>src/hosts/electron/ElectronPrismController.ts</code> <a class="header-anchor" href="#src-hosts-electron-electronprismcontroller-ts" aria-label="Permalink to “src/hosts/electron/ElectronPrismController.ts”">​</a></h2><p>A thin platform shell (45 lines) that extends <code>BasePrismController</code> from <code>packages/prism-core/</code>. The bulk of orchestration logic (state management, services, handler routing) now lives in the base class. This file provides only Electron-specific overrides.</p><h2 id="vscode-api-replacements" tabindex="-1">VSCode API Replacements <a class="header-anchor" href="#vscode-api-replacements" aria-label="Permalink to “VSCode API Replacements”">​</a></h2><table tabindex="0"><thead><tr><th>VSCode API</th><th>Electron Replacement</th></tr></thead><tbody><tr><td><code>vscode.EventEmitter</code></td><td>Node.js <code>EventEmitter</code></td></tr><tr><td><code>vscode.workspace.workspaceFolders</code></td><td>Stored <code>_projectDir</code> string via <code>setProjectDir()</code></td></tr><tr><td><code>vscode.workspace.fs.stat()</code></td><td><code>fs.stat()</code> from <code>fs/promises</code></td></tr><tr><td><code>vscode.FileSystemWatcher</code></td><td><code>PrismWatcher</code> (chokidar)</td></tr><tr><td><code>vscode.commands.executeCommand(&#39;setContext&#39;, ...)</code></td><td>No-op (context keys not applicable)</td></tr><tr><td><code>vscode.window.showInformationMessage</code></td><td>Not needed (UI handles all messaging)</td></tr></tbody></table><h2 id="services" tabindex="-1">Services <a class="header-anchor" href="#services" aria-label="Permalink to “Services”">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Class</th><th>Purpose</th></tr></thead><tbody><tr><td>Workflow</td><td><code>WorkflowStateMachine</code></td><td>Research → Plan → Implement → Validate state machine</td></tr><tr><td>Stories</td><td><code>StoriesManager</code></td><td>Load/parse stories.json, track completion</td></tr><tr><td>Watcher</td><td><code>PrismWatcher</code></td><td>chokidar-based file system monitoring for <code>.prism/</code></td></tr><tr><td>Chat</td><td><code>ClaudeRunner</code></td><td>Spawn Claude CLI for chat sessions</td></tr><tr><td>Skills</td><td><code>ModeBridge</code></td><td>Route <code>/skill-name</code> commands to Claude CLI</td></tr><tr><td>Spectrum</td><td><code>SpectrumEngine</code> + <code>SpectrumRunner</code></td><td>Autonomous story execution loop</td></tr></tbody></table><h2 id="handler-registry" tabindex="-1">Handler Registry <a class="header-anchor" href="#handler-registry" aria-label="Permalink to “Handler Registry”">​</a></h2><p>All handlers are registered in <code>_registerHandlers()</code> and dispatched via <code>handleGrpcRequest()</code>:</p><h3 id="stateservice" tabindex="-1">StateService <a class="header-anchor" href="#stateservice" aria-label="Permalink to “StateService”">​</a></h3><table tabindex="0"><thead><tr><th>Handler</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>subscribeToState</code></td><td>Streaming</td><td>Push state updates indefinitely to subscriber</td></tr><tr><td><code>getState</code></td><td>Unary</td><td>One-shot state fetch</td></tr></tbody></table><h3 id="uiservice" tabindex="-1">UiService <a class="header-anchor" href="#uiservice" aria-label="Permalink to “UiService”">​</a></h3><table tabindex="0"><thead><tr><th>Handler</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>initializeWebview</code></td><td>Unary</td><td>Trigger <code>.prism/</code> detection, push initial state</td></tr><tr><td><code>initPrism</code></td><td>Unary</td><td>Create <code>.prism/</code> directory structure</td></tr></tbody></table><h3 id="workflowservice" tabindex="-1">WorkflowService <a class="header-anchor" href="#workflowservice" aria-label="Permalink to “WorkflowService”">​</a></h3><table tabindex="0"><thead><tr><th>Handler</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>transition</code></td><td>Unary</td><td>Move to next workflow phase</td></tr><tr><td><code>getAvailableTransitions</code></td><td>Unary</td><td>Query valid transitions from current state</td></tr></tbody></table><h3 id="chatservice" tabindex="-1">ChatService <a class="header-anchor" href="#chatservice" aria-label="Permalink to “ChatService”">​</a></h3><table tabindex="0"><thead><tr><th>Handler</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>sendMessage</code></td><td>Unary</td><td>Route message to Claude CLI or plugin skill</td></tr><tr><td><code>abortTask</code></td><td>Unary</td><td>Terminate running chat session</td></tr><tr><td><code>clearMessages</code></td><td>Unary</td><td>Reset chat history</td></tr></tbody></table><h3 id="pluginservice" tabindex="-1">PluginService <a class="header-anchor" href="#pluginservice" aria-label="Permalink to “PluginService”">​</a></h3><table tabindex="0"><thead><tr><th>Handler</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>executeSkill</code></td><td>Unary</td><td>Run <code>/skill-name</code> via ModeBridge → Claude CLI</td></tr><tr><td><code>terminateSkill</code></td><td>Unary</td><td>Stop running skill</td></tr><tr><td><code>checkCli</code></td><td>Unary</td><td>Verify Claude CLI is on PATH</td></tr><tr><td><code>getSkills</code></td><td>Unary</td><td>List available Prism plugin skills</td></tr></tbody></table><h3 id="spectrumservice" tabindex="-1">SpectrumService <a class="header-anchor" href="#spectrumservice" aria-label="Permalink to “SpectrumService”">​</a></h3><table tabindex="0"><thead><tr><th>Handler</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>start</code></td><td>Unary</td><td>Begin autonomous story execution loop</td></tr><tr><td><code>pause</code></td><td>Unary</td><td>Pause execution</td></tr><tr><td><code>resume</code></td><td>Unary</td><td>Resume paused execution</td></tr><tr><td><code>stop</code></td><td>Unary</td><td>Stop execution</td></tr><tr><td><code>skipStory</code></td><td>Unary</td><td>Mark current story as SKIPPED, advance</td></tr><tr><td><code>reset</code></td><td>Unary</td><td>Reset execution state</td></tr></tbody></table><h2 id="state-management" tabindex="-1">State Management <a class="header-anchor" href="#state-management" aria-label="Permalink to “State Management”">​</a></h2><p>The controller maintains a <code>PrismExtensionState</code> object and broadcasts changes to all subscribers:</p><div class="language-typescript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">async </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">updateState</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(partial: Partial</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PrismExtensionState</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">): </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Promise</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;void&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Object.assign(this._state, partial);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  this._broadcastState();</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Subscribers are tracked by <code>request_id</code>. Dead subscribers are auto-cleaned on send failure.</p><h2 id="key-methods" tabindex="-1">Key Methods <a class="header-anchor" href="#key-methods" aria-label="Permalink to “Key Methods”">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Purpose</th></tr></thead><tbody><tr><td><code>setProjectDir(dir)</code></td><td>Set active project, trigger <code>.prism/</code> re-detection, start watcher</td></tr><tr><td><code>updateState(partial)</code></td><td>Merge partial state, broadcast to all subscribers</td></tr><tr><td><code>setPhase(phase)</code></td><td>Force workflow phase transition</td></tr><tr><td><code>_detectPrismDir()</code></td><td>Check for <code>.prism/</code>, detect stories.json, start file watcher</td></tr><tr><td><code>_onPrismFileChange(event)</code></td><td>React to stories.json changes, reload stories</td></tr><tr><td><code>_runChatSession(text)</code></td><td>Spawn ClaudeRunner, stream text + tool events</td></tr><tr><td><code>_startSpectrumLoop(config)</code></td><td>Initialize SpectrumEngine, begin iteration loop</td></tr><tr><td><code>dispose()</code></td><td>Terminate all runners, close watchers, clean up subscribers</td></tr></tbody></table>`,27)])])}const b=e(s,[["render",o]]);export{m as __pageData,b as default};
